module top_module(
    input Clk,ShiftIn,load,ShiftEn,
    input [3:0] ParallelIn,
    output ShiftOut, 
    output [3:0] RegContent
    );reg [3:0] obf_shift_reg;
    always @(posedge Clk)
        if(load)
            obf_shift_reg <= ParallelIn;
        else if (ShiftEn)
            obf_shift_reg <= {obf_shift_reg[2:0], ShiftIn};
    assign ShiftOut = obf_shift_reg[3];
    assign RegContent = obf_shift_reg;
endmodule
